SELECT EANCodeLabelsTMP.*, ImmaginiPerEtichetteScatola.[Linked Document], Item.[Line Code], MasterdataQuelloGiusto.[Codice Articolo _QUELLOGIUSTO], MasterdataQuelloGiusto.[Corrispondenza EAN_QUELLOGIUSTO ], MasterdataQuelloGiusto.[Retail Price_QUELLO GIUSTO], MasterdataQuelloGiusto.[Retail Price con Fidelity card], MasterdataQuelloGiusto.[codice veloce], MasterdataQuelloGiusto.[STAGIONE ]
FROM ((EANCodeLabelsTMP LEFT JOIN ImmaginiPerEtichetteScatola ON (EANCodeLabelsTMP.Color = ImmaginiPerEtichetteScatola.[Constant Variable Code]) AND (EANCodeLabelsTMP.Article = ImmaginiPerEtichetteScatola.[Source No_])) LEFT JOIN Item ON EANCodeLabelsTMP.Article = Item.No_) LEFT JOIN MasterdataQuelloGiusto ON (EANCodeLabelsTMP.Size = MasterdataQuelloGiusto.Taglia) AND (EANCodeLabelsTMP.Color = MasterdataQuelloGiusto.[Color Code]) AND (EANCodeLabelsTMP.Article = MasterdataQuelloGiusto.Article);

